FormScriptItem.Script:
/**
 * FormValidation.js
 * Validates each field individually or as a group
 *
 * @param {string} ControlName Field name to validate, null to validate all fields
 *
 * FieldsToValidate is an object where every property is the name of
 * the field to validate.
 *
 * var FieldsToValidate = {
 *    FieldName: [{
 *    Type: "Name of the validation type to apply to the field.
 *          Look for available validation types in CentralValidation.js"
 *    ErrorMsg: "Error message to display to the user"
 * }],
 *    FieldName2: [{...},{...}]
 * }
 */

// Add the fields to validate here
var FieldsToValidate = {
  Name: [
    {
      Type: "Blank",
      ErrorMsg: "A value needs to be entered.",
    },
  ],
  Phone: [
    {
      Type: "Blank",
      ErrorMsg: "A value needs to be entered.",
    },
  ],
  BirthDate: [
    {
      Type: "Blank",
      ErrorMsg: "A value needs to be entered.",
    },
    {
      Type: "LegalMajority",
      ErrorMsg: "Must be, at least, 18 years old.",
    },
  ],
  Email: [
    {
      Type: "Blank",
      ErrorMsg: "A value needs to be entered.",
    },
    {
      Type: "Email",
      ErrorMsg: "Enter a valid email address.",
    },
  ],
  SelectFeature: [
    {
      Type: "Select",
      ErrorMsg: "Select a feature.",
    },
  ],
  OtherDescription: [
    {
      Type: "Blank",
      ErrorMsg: "Enter your most valuable feature.",
      // Boolean expression:
      Validate: VV.Form.GetFieldValue("SelectFeature") === "Other",
    },
  ],
};

// No need to make changes bellow this line
function Validate(FieldsToValidate, ControlName) {
  var RunAll = ControlName == null ? true : false;
  var PassValidation = true;
  var FieldIsValid;

  var FieldErrorCue = function (FieldName, FieldIsValid, ErrorMsg) {
    if (FieldIsValid) {
      VV.Form.ClearValidationErrorOnField(FieldName);
    } else {
      VV.Form.SetValidationErrorMessageOnField(FieldName, ErrorMsg);
    }
  };

  if (RunAll) {
    // Validates every field
    for (var Field in FieldsToValidate) {
      for (
        let index = 0;
        index < FieldsToValidate[Field].length && PassValidation;
        index++
      ) {
        // If the "Validate" property is defined, use that value
        var requiresValidation =
          FieldsToValidate[Field][index].Validate !== undefined
            ? FieldsToValidate[Field][index].Validate
            : true;

        if (requiresValidation) {
          FieldIsValid = VV.Form.Global.CentralValidation(
            VV.Form.GetFieldValue(Field),
            FieldsToValidate[Field][index].Type
          );
          if (!FieldIsValid) {
            PassValidation = false;
          }

          FieldErrorCue(
            Field,
            FieldIsValid,
            FieldsToValidate[Field][index].ErrorMsg
          );
        }
      }
    }
  } else {
    // Validates only the field sent as parameter
    for (
      let index = 0;
      index < FieldsToValidate[ControlName].length && PassValidation;
      index++
    ) {
      // If the "Validate" property is defined, use that value
      var requiresValidation =
        FieldsToValidate[ControlName][index].Validate !== undefined
          ? FieldsToValidate[ControlName][index].Validate
          : true;

      if (requiresValidation) {
        PassValidation = VV.Form.Global.CentralValidation(
          VV.Form.GetFieldValue(ControlName),
          FieldsToValidate[ControlName][index].Type
        );

        FieldErrorCue(
          ControlName,
          PassValidation,
          FieldsToValidate[ControlName][index].ErrorMsg
        );
      }
    }
  }
  return PassValidation;
}

return Validate(FieldsToValidate, ControlName);

var OtherIsValid = VV.Form.Template.FormValidation("OtherDescription");
var SelectFeatureIsValid = VV.Form.Template.FormValidation("SelectFeature");

if (OtherIsValid && SelectFeatureIsValid) {
  VV.Form.SetFieldValue("StepCounter", -1, true);
}

var BirthDateValue = VV.Form.GetFieldValue("BirthDate");
var Today = new Date();
Today.toString();

// Calculate age
var AgeValue = VV.Form.Global.Age(BirthDateValue, Today);
VV.Form.SetFieldValue("Age", AgeValue, true);

// Validate
VV.Form.Template.FormValidation("BirthDate");

var BirthDateValue = VV.Form.GetFieldValue("BirthDate");

// Calculate age
var AgeValue = VV.Form.Global.Age(BirthDateValue);
VV.Form.SetFieldValue("Age", AgeValue, true);

// Validate
VV.Form.Template.FormValidation("BirthDate");

if (VV.Form.Template.FormValidation()) {
  VV.Form.DoPostbackSave();
} else {
  var messageData =
    "All of the fields have not been filled in completely or there is an issue with the range of the data entered.  Highlight your mouse over the red icon to see how you can resolve the error stopping you from saving this form.";
  VV.Form.Global.DisplayMessaging(messageData, "Missing Information");
}

var phone_enteredValue = VV.Form.GetFieldValue("Phone");
var phone_formattedVal = VV.Form.Global.FormatPhone(phone_enteredValue);

if (phone_formattedVal != phone_enteredValue) {
  VV.Form.SetFieldValue("Phone", phone_formattedVal);
} else {
  VV.Form.Template.FormValidation("Phone");
}

var PhoneIsValid = VV.Form.Template.FormValidation("Phone");
var EmailIsValid = VV.Form.Template.FormValidation("Email");
var NameIsValid = VV.Form.Template.FormValidation("Name");
var BirthDateIsValid = VV.Form.Template.FormValidation("BirthDate");

if (PhoneIsValid && EmailIsValid && NameIsValid && BirthDateIsValid) {
  VV.Form.SetFieldValue("StepCounter", 2, true);
}
